                className="inline-flex items-center justify-center rounded-full border border-[hsl(var(--border))] px-6 py-3 font-body type-body font-medium text-[hsl(var(--fg))] transition hover:border-[hsl(var(--teal))]/40 hover:bg-[hsl(var(--teal))]/5"
