function SignalMeter({ label, angle }: { label: string; angle: number }) {
  const cx = 36;
  const cy = 34;
  const radius = 26;
  const strokeWidth = 8;
  const capRadius = strokeWidth / 2;
  const needleLength = 17;
  const greenShare = 100 / 3;
  const yellowShare = 100 / 3;
  const redShare = 100 - greenShare - yellowShare;
  const topArcPath = "M 10 34 A 26 26 0 0 1 62 34";

  const polarToCartesian = (degrees: number, length: number) => {
    const radians = (degrees * Math.PI) / 180;
    return {
      x: cx + Math.cos(radians) * length,
      y: cy - Math.sin(radians) * length,
    };
  };

  const leftCap = polarToCartesian(180, radius);
  const rightCap = polarToCartesian(0, radius);
  const needleTip = polarToCartesian(angle, needleLength);

  return (
    <div className="flex items-center gap-3">
      <svg
        viewBox="0 0 72 46"
        className="h-11 w-16 shrink-0"
        aria-hidden="true"
      >
        <path
          d={topArcPath}
          fill="none"
          stroke="#5AC11C"
          strokeWidth={strokeWidth}
          strokeLinecap="butt"
          pathLength={100}
          strokeDasharray={`${greenShare} ${100 - greenShare}`}
        />
        <path
          d={topArcPath}
          fill="none"
          stroke="#F5BF19"
          strokeWidth={strokeWidth}
          strokeLinecap="butt"
          pathLength={100}
          strokeDasharray={`${yellowShare} ${100 - yellowShare}`}
          strokeDashoffset={-greenShare}
        />
        <path
          d={topArcPath}
          fill="none"
          stroke="#E3342F"
          strokeWidth={strokeWidth}
          strokeLinecap="butt"
          pathLength={100}
          strokeDasharray={`${redShare} ${100 - redShare}`}
          strokeDashoffset={-(greenShare + yellowShare)}
        />
        <circle cx={leftCap.x} cy={leftCap.y} r={capRadius} fill="#5AC11C" />
        <circle cx={rightCap.x} cy={rightCap.y} r={capRadius} fill="#E3342F" />
        <path
          d={`M ${cx} ${cy} L ${needleTip.x.toFixed(2)} ${needleTip.y.toFixed(2)}`}
          stroke="#22304C"
          strokeWidth="3.5"
          strokeLinecap="round"
        />
        <circle cx={cx} cy={cy} r="5" fill="#22304C" />
      </svg>
      <div>
        <p className="font-body text-[10px] font-semibold uppercase tracking-[0.12em] text-[hsl(var(--muted))]">
          Challenge signal
        </p>
        <p className="mt-1 font-body text-[13px] font-medium leading-none text-[hsl(var(--fg))]">
          {label}
        </p>
      </div>
    </div>
  );
}

